module div_8bit (
    input wire clk,
    input wire rst,
    input wire [7:0] dividend,
    input wire [7:0] divisor,
    input wire sign,
    input wire opn_valid,
    output reg res_valid,
    input wire res_ready,
    output reg [15:0] result
);

    reg [7:0] dividend_reg, divisor_reg;
    reg [15:0] SR;
    reg [3:0] cnt;
    reg [7:0] NEG_DIVISOR;
    reg start_cnt;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            res_valid <= 0;
            result <= 0;
            cnt <= 0;
            start_cnt <= 0;
        end
        else if (opn_valid && !res_valid) begin
            dividend_reg <= dividend;
            divisor_reg <= divisor;
            SR <= {1'b0, dividend_reg} << 1;
            NEG_DIVISOR <= sign ? -divisor_reg : divisor_reg;
            cnt <= 1;
            start_cnt <= 1;
        end
        else if (start_cnt) begin
            if (cnt == 8) begin
                cnt <= 0;
                start_cnt <= 0;
                result <= SR[15:0];
            end
            else begin
                cnt <= cnt + 1;
                {SR, NEG_DIVISOR} <= {SR[14:0], NEG_DIVISOR[7:0]};
            end
        end
        else if (res_valid && res_ready) begin
            res_valid <= 0;
        end
        else begin
            res_valid <= res_valid;
        end
    end

endmodule
